import { useState } from "react";
import axios from "axios";

const API = "http://127.0.0.1:5000";

const theme = {
  bg: "#0f172a",
  sidebar: "#020617",
  card: "#1e293b",
  text: "#f1f5f9",
  border: "#334155",
};

export default function App() {
  const [email, setEmail] = useState("");
  const [apiKey, setApiKey] = useState("");
  const [usage, setUsage] = useState([]);
  const [response, setResponse] = useState("");
  const [rateLimitHit, setRateLimitHit] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");

  const signup = async () => {
    try {
      setLoading(true);
      const res = await axios.post(`${API}/auth/signup`, { email });
      setApiKey(res.data.apiKey);
      setMessage("✅ API Key Generated");
    } catch {
      setMessage("❌ Failed to generate API key");
    } finally {
      setLoading(false);
    }
  };

  const callAPI = async () => {
    if (usage.length >= 5) {
      setRateLimitHit(true);
      return;
    }

    try {
      setLoading(true);
      const res = await axios.get(
        `${API}/proxy?url=https://jsonplaceholder.typicode.com/todos/1&apiKey=${apiKey}`
      );
      setResponse(JSON.stringify(res.data, null, 2));
      setMessage("✅ API call successful");
      setRateLimitHit(false);
    } catch {
      setMessage("❌ API call failed");
    } finally {
      setLoading(false);
    }
  };

  const fetchUsage = async () => {
    try {
      setLoading(true);
      const res = await axios.get(`${API}/usage/${apiKey}`);
      setUsage(res.data);
      setMessage("📊 Usage loaded");
    } catch {
      setMessage("❌ Failed to load usage");
    } finally {
      setLoading(false);
    }
  };

  const copyKey = () => {
    navigator.clipboard.writeText(apiKey);
    setMessage("📋 API Key copied!");
  };

  const billing = (usage.length * 0.2).toFixed(2);

  return (
    <div style={styles.container}>

      {/* Sidebar */}
      <div style={styles.sidebar}>
        <h2 style={{ marginBottom: "30px" }}>🚀 MeterFlow</h2>
        <p>Dashboard</p>
        <p>API Keys</p>
        <p>Usage</p>
        <p>Billing</p>
      </div>

      {/* Main */}
      <div style={styles.main}>
        <h1>Developer Dashboard</h1>

        {message && <p style={styles.message}>{message}</p>}

        {/* Cards */}
        <div style={styles.cards}>
          <div style={styles.card}>
            <h4>Total Requests</h4>
            <h2>{usage.length}</h2>
          </div>

          <div style={styles.card}>
            <h4>Status</h4>
            <h2 style={{ color: rateLimitHit ? "#ef4444" : "#22c55e" }}>
              {rateLimitHit ? "Limit Hit" : "Active"}
            </h2>
          </div>

          <div style={styles.card}>
            <h4>Billing</h4>
            <h2>₹{billing}</h2>
          </div>
        </div>

        {/* API Key */}
        <div style={styles.section}>
          <h3>Generate API Key</h3>
          <input
            placeholder="Enter email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            style={styles.input}
          />

          <button
            style={styles.btnBlue}
            onClick={signup}
            disabled={loading || !email}
          >
            {loading ? "Generating..." : "Generate"}
          </button>

          {apiKey && (
            <div style={styles.key}>
              {apiKey}
              <button style={styles.copyBtn} onClick={copyKey}>
                Copy
              </button>
            </div>
          )}
        </div>

        {/* API Playground */}
        {apiKey && (
          <div style={styles.section}>
            <h3>API Playground</h3>

            <button
              style={styles.btnGreen}
              onClick={callAPI}
              disabled={loading}
            >
              {loading ? "Calling..." : "Call API"}
            </button>

            <button
              style={styles.btnPurple}
              onClick={fetchUsage}
              disabled={loading}
            >
              Load Usage
            </button>

            {rateLimitHit && (
              <p style={{ color: "#ef4444" }}>
                ⚠ Rate limit exceeded (5 requests max)
              </p>
            )}

            {response && <pre style={styles.pre}>{response}</pre>}
          </div>
        )}

        {/* Usage Table */}
        {usage.length > 0 && (
          <div style={styles.section}>
            <h3>Usage Logs</h3>
            <table style={styles.table}>
              <thead>
                <tr>
                  <th>URL</th>
                  <th>Status</th>
                  <th>Time</th>
                </tr>
              </thead>
              <tbody>
                {usage.map((u, i) => (
                  <tr key={i}>
                    <td>{u.url}</td>
                    <td>{u.status}</td>
                    <td>{new Date(u.timestamp).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: { display: "flex", height: "100vh", fontFamily: "Segoe UI", background: theme.bg },
  sidebar: { width: "240px", background: theme.sidebar, color: theme.text, padding: "20px" },
  main: { flex: 1, padding: "30px", color: theme.text },

  message: { margin: "10px 0", color: "#38bdf8" },

  cards: { display: "flex", gap: "15px", marginBottom: "20px" },
  card: {
    background: theme.card,
    padding: "20px",
    borderRadius: "12px",
    flex: 1,
    transition: "0.3s",
  },

  section: { background: theme.card, padding: "20px", marginBottom: "20px", borderRadius: "12px" },

  input: { padding: "10px", marginRight: "10px", borderRadius: "6px" },

  key: {
    marginTop: "10px",
    background: "#020617",
    padding: "12px",
    borderRadius: "6px",
    display: "flex",
    justifyContent: "space-between",
  },

  copyBtn: {
    background: "#334155",
    color: "white",
    border: "none",
    padding: "5px 10px",
    cursor: "pointer",
  },

  btnBlue: { background: "#6366f1", color: "white", padding: "10px", border: "none", cursor: "pointer" },
  btnGreen: { background: "#22c55e", color: "white", padding: "10px", border: "none", marginRight: "10px" },
  btnPurple: { background: "#a855f7", color: "white", padding: "10px", border: "none" },

  pre: { background: "#020617", color: "#22c55e", padding: "10px", marginTop: "10px" },

  table: { width: "100%", marginTop: "10px" },
};
